import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();

  const initialFormState = {
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    loaiHinhCheBienGo: '', nguonGocGo: '',
    loaiCoSoDangKy: '',
    tenLamSanList: [], // Sửa ở đây: chọn nhiều loài
    issueDate: '', expiryDate: '',
    trangThai: 'Đang hoạt động',
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    // ... giữ nguyên logic
  }, [navigate]);

  const handleChange = useCallback((e) => {
    const { name, value, multiple, options } = e.target;
    if (multiple) {
      const selected = Array.from(options).filter(o => o.selected).map(o => o.value);
      setFormData(prev => ({ ...prev, [name]: selected }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormState);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });

    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập. Vui lòng đăng nhập lại.' });
      setLoading(false);
      navigate('/login');
      return;
    }

    try {
      const submissionData = { ...formData };
      submissionData.products = [];

      if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
        for (const ten of submissionData.tenLamSanList) {
          submissionData.products.push({
            tenLamSan: ten,
            tenKhoaHoc: speciesOptions.find(s => s.name === ten)?.scientificName || '',
            khoiLuong: submissionData.tongDan,
            donViTinh: 'cá thể',
            mucDichNuoi: submissionData.mucDichNuoi,
            hinhThucNuoi: submissionData.hinhThucNuoi,
            maSoCoSoGayNuoi: submissionData.maSoCoSoGayNuoi
          });
        }
      } else if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
        for (const ten of submissionData.tenLamSanList) {
          submissionData.products.push({
            tenLamSan: ten,
            tenKhoaHoc: submissionData.tenKhoaHoc,
            khoiLuong: submissionData.khoiLuong,
            donViTinh: 'm³',
            loaiHinhCheBienGo: submissionData.loaiHinhCheBienGo,
            nguonGocGo: submissionData.nguonGocGo
          });
        }
      }

      const fieldsToDelete = [
        'tenLamSanList', 'tenKhoaHoc', 'khoiLuong', 'tongDan', 'loaiHinhCheBienGo',
        'nguonGocGo', 'mucDichNuoi', 'hinhThucNuoi', 'maSoCoSoGayNuoi'
      ];
      fieldsToDelete.forEach(field => delete submissionData[field]);

      const response = await axios.post('http://localhost:10000/api/farms', submissionData, {
        headers: { Authorization: `Bearer ${token}` }
      });

      setSuccessMessage('Đăng ký cơ sở thành công!');
      setMessage({ type: 'success', text: 'Đăng ký cơ sở thành công!' });
      resetForm();
    } catch (err) {
      setMessage({ type: 'error', text: 'Đã xảy ra lỗi khi gửi dữ liệu.' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở</h2>
      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* ... các trường khác ... */}

        {/* Trường chọn nhiều loài */}
        <label>Chọn loài nuôi (nhiều):</label>
        <select
          multiple
          name="tenLamSanList"
          value={formData.tenLamSanList}
          onChange={handleChange}
        >
          {speciesOptions.map((sp, idx) => (
            <option key={idx} value={sp.name}>{sp.name}</option>
          ))}
        </select>

        {/* ... các trường khác ... */}

        <button type="submit" disabled={loading}>
          {loading ? 'Đang gửi...' : 'Gửi đăng ký'}
        </button>
        {message.text && (
          <p className={message.type === 'error' ? 'error' : 'success'}>
            {message.text}
          </p>
        )}
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
